const rows = [];
const POS = /(love|amazing|great|awesome|beautiful|nice|good|wow|incredible|fantastic|cool|perfect|best|вқӨ|рҹҳҚ|рҹ”Ҙ|рҹ‘Ҹ|рҹ’ҷ|рҹ’ң|рҹҷӮ|рҹҳ„|рҹҘ°)/i;
const NEG = /(hate|bad|terrible|awful|ugly|worst|sad|angry|stupid|disgusting|рҹҳЎ|рҹҳӯ|рҹ‘Һ|broken|fail|horr)/i;
for (const item of $input.all()) {
  const d = item.json || {};
  const text = d.text || '';
  const likes = Number(d.likesCount) || 0;
  const replies = Number(d.repliesCount) || 0;
  let sentiment = 'neutral';
  if (POS.test(text)) sentiment = 'positive';
  if (NEG.test(text)) sentiment = 'negative';
  if (POS.test(text) && NEG.test(text)) sentiment = 'mixed';
  const owner = d.owner || {};
  rows.push({ json: {
    sentiment, likes_count: likes, replies_count: replies,
    commenter: d.ownerUsername || (owner.username || ''),
    is_verified: owner.is_verified ? 'yes' : 'no',
    comment_text: text.slice(0, 500),
    comment_id: d.id || '', comment_url: d.commentUrl || '',
    post_url: d.postUrl || '', timestamp: d.timestamp || ''
  }});
}
rows.sort((a, b) => b.json.likes_count - a.json.likes_count);
rows.forEach((r, i) => { r.json.rank = i + 1; });
return rows;

const item = $input.first();
if (item.binary && item.binary.data) { item.binary.data.fileName = 'instagram-comments.xlsx'; }
return item;

const rows = $input.first().json.data || [];
const arr = Array.isArray(rows) ? rows : [];
const total = arr.length;
const pos = arr.filter(r => r.sentiment === 'positive').length;
const neg = arr.filter(r => r.sentiment === 'negative').length;
const neu = arr.filter(r => r.sentiment === 'neutral').length;
const top = arr.slice(0, 10);
const rowsHtml = top.map((r, i) => '<tr><td>'+(i+1)+'</td><td>'+r.sentiment+'</td><td>'+(r.likes_count||0)+'</td><td>'+(r.commenter||'')+'</td><td>'+(r.comment_text||'').slice(0,80).replace(/</g,'&lt;')+'</td></tr>').join('');
const html = '<h2>Instagram Comments Report</h2><p><b>'+total+'</b> comments scraped. Sentiment: <b>'+pos+'</b> positive, <b>'+neg+'</b> negative, <b>'+neu+'</b> neutral.</p><table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:13px;"><thead><tr style="background:#f0f0f0"><th>#</th><th>Sentiment</th><th>Likes</th><th>Commenter</th><th>Comment</th></tr></thead><tbody>'+rowsHtml+'</tbody></table><p style="color:#666;font-size:12px;margin-top:16px;">Full dataset attached as instagram-comments.xlsx. Sentiment is a heuristic keyword/emoji match, not ML. Generated by CoreClaw + n8n.</p>';
return [{ json: { html, total, pos, neg, neu } }];
